import { describe, expect, it } from 'vitest';
import { EvmContracts } from '@argonprotocol/mainchain';
import { encodeFunctionData } from 'viem';

const REQUEST = {
  argonAccountId: `0x${'22'.repeat(32)}`,
  argonTransferNonce: 1n,
  chainId: 1n,
  microgonsPerArgonot: 7n,
  recipient: `0x${'55'.repeat(20)}`,
  validUntilBlock: 10n,
  token: `0x${'44'.repeat(20)}`,
  amount: 25n,
  mintingAuthorityTip: 1n,
} as const;

const GATEWAY = {
  chainId: 1n,
  gatewayAddress: `0x${'11'.repeat(20)}`,
} as const;

const AUTHORIZATION = {
  request: REQUEST,
  microgonCollateral: 16n,
  micronotCollateral: 0n,
} as const;

const FINALIZE_PROOF = {
  authorizations: [
    {
      microgonCollateral: 16n,
      micronotCollateral: 0n,
      signature: `0x${'33'.repeat(65)}`,
    },
  ],
} as const;

describe('Ethereum contract vectors', () => {
  it('pins transfer-out hashes and finalize calldata to a known vector', () => {
    expect(EvmContracts.hashMintingGatewayTransferOutOfArgonRequest(REQUEST)).toBe(
      '0x15547a58403a407ace23aaafbc0343f0221b1564405e9974f692e5f25b9b08ce',
    );
    expect(EvmContracts.hashMintingGatewayMintingAuthorization(GATEWAY, AUTHORIZATION)).toBe(
      '0x94fb1ef1202e2f7b0e2943219453e28153d2a97069bdb48ce28a695a6cf3bbb8',
    );
    expect(
      encodeFunctionData({
        abi: EvmContracts.mintingGatewayAbi,
        functionName: 'finalizeTransferOutOfArgon',
        args: [REQUEST, FINALIZE_PROOF],
      }),
    ).toBe(
      '',
    );
  });

  it('changes the transfer request hash when microgonsPerArgonot changes', () => {
    expect(
      EvmContracts.hashMintingGatewayTransferOutOfArgonRequest({
        ...REQUEST,
        microgonsPerArgonot: REQUEST.microgonsPerArgonot + 1n,
      }),
    ).not.toBe(EvmContracts.hashMintingGatewayTransferOutOfArgonRequest(REQUEST));
  });
});
